def cal_sum(n):
    if n == 0:
        return 3
    elif n == 1:
        return 0
    elif n == 2:
        return 2
    else:
        p = [3, 0, 2]
        for i in range(3, n+1):
            p.append(p[i-2] + p[i-3])
        return sum(p[:n])

assert cal_sum(9) == 49
assert cal_sum(10) == 66
assert cal_sum(11) == 88

